  1	import React, { ReactNode, Suspense, useContext, useMemo, useState } from 'react';
  2	import { dump } from 'js-yaml';
  3	
  4	import { PATHS_TO_HIGHLIGHT } from '@kubevirt-utils/resources/vm/utils/constants';
  5	import { K8sResourceCommon, YAMLEditor } from '@openshift-console/dynamic-plugin-sdk';
  6	import {
  7	  Alert,
  8	  AlertActionCloseButton,
  9	  AlertVariant,
 10	  Button,
 11	  ButtonVariant,
 12	  Flex,
 13	  FlexItem,
 14	  Sidebar,
 15	  SidebarContent,
 16	  SidebarPanel,
 17	  Stack,
 18	  StackItem,
 19	} from '@patternfly/react-core';
 20	
 21	import Loading from '../Loading/Loading';
 22	
 23	import { SidebarEditorContext } from './SidebarEditorContext';
 24	import { useEditorHighlighter } from './useEditorHighlighter';
 25	import { safeLoad } from './utils';
 26	
 27	import './sidebar-editor.scss';
 28	
 29	type SidebarEditorProps<Resource> = {
 30	  children: ((resource: Resource) => ReactNode) | ReactNode | ReactNode[];
 31	  onChange?: (resource: Resource) => void;
 32	  onResourceUpdate?: (newResource: Resource) => Promise<Resource | void>;
 33	  pathsToHighlight?: string[];
 34	  resource: Resource;
 35	};
 36	
 37	const SidebarEditor = <Resource extends K8sResourceCommon>({
 38	  children,
 39	  onChange,
 40	  onResourceUpdate,
 41	  pathsToHighlight = PATHS_TO_HIGHLIGHT.DEFAULT,
 42	  resource,
 43	}: SidebarEditorProps<Resource>): JSX.Element => {
 44	  const [editableYAML, setEditableYAML] = useState('');
 45	  const [loading, setLoading] = useState(false);
 46	  const [error, setError] = useState(null);
 47	  const [success, setSuccess] = useState(false);
 48	
 49	  const resourceYAML = useMemo(() => {
 50	    const yaml = dump(resource, { forceQuotes: true, skipInvalid: true });
 51	    setEditableYAML(yaml);
 52	    return yaml;
 53	  }, [resource]);
 54	
 55	  const { isEditable, showEditor } = useContext(SidebarEditorContext);
 56	  const editedResource = safeLoad<Resource>(editableYAML);
 57	  const editorRef = useEditorHighlighter(editableYAML, pathsToHighlight, showEditor);
 58	
 59	  const changeResource = (newValue: string) => {
 60	    setEditableYAML(newValue);
 61	
 62	    if (onChange) onChange(safeLoad<Resource>(newValue));
 63	    return {};
 64	  };
 65	
 66	  const onUpdate = (newResource: Resource) => {
 67	    if (!onResourceUpdate) return;
 68	
 69	    setSuccess(false);
 70	    setError(null);
 71	    setLoading(true);
 72	    return onResourceUpdate(newResource)
 73	      .then(() => setSuccess(true))
 74	      .catch(setError)
 75	      .finally(() => setLoading(false));
 76	  };
 77	
 78	  const onReload = () => {
 79	    setSuccess(false);
 80	    setError(null);
 81	    setEditableYAML(resourceYAML);
 82	  };
 83	
 84	  return (
 85	    <Sidebar className="sidebar-editor" hasGutter hasNoBackground isPanelRight>
 86	      <SidebarContent>
 87	        {children instanceof Function ? children(editedResource ?? resource) : children}
 88	      </SidebarContent>
 89	      {showEditor && (
 90	        <SidebarPanel
 91	          className="sidebar-editor__panel"
 92	          width={{ default: 'width_33', lg: 'width_50', xl: 'width_50' }}
 93	        >
 94	          <Stack hasGutter>
 95	            <StackItem isFilled>
 96	              <Suspense fallback={<Loading />}>
 97	                <YAMLEditor
 98	                  minHeight="300px"
 99	                  onChange={changeResource}
100	                  onSave={() => onUpdate(editedResource)}
101	                  options={{ readOnly: !isEditable }}
102	                  ref={editorRef}
103	                  value={editableYAML}
104	                />
105	              </Suspense>
106	            </StackItem>
107	            {(success || error) && (
108	              <StackItem>
109	                {success && (
110	                  <Alert
111	                    actionClose={<AlertActionCloseButton onClose={() => setSuccess(false)} />}
112	                    title="Success"
113	                    variant={AlertVariant.success}
114	                  ></Alert>
115	                )}
116	                {error && (
117	                  <Alert title="Error" variant={AlertVariant.danger}>
118	                    {error.message}
119	                  </Alert>
120	                )}
121	              </StackItem>
122	            )}
123	            {onResourceUpdate && isEditable && (
124	              <StackItem>
125	                <Flex>
126	                  <FlexItem>
127	                    <Button
128	                      className="save-button"
129	                      isLoading={loading}
130	                      onClick={() => onUpdate(editedResource)}
131	                      variant={ButtonVariant.primary}
132	                    >
133	                      Save
134	                    </Button>
135	                  </FlexItem>
136	                  <FlexItem>
137	                    <Button
138	                      className="reload-button"
139	                      onClick={onReload}
140	                      variant={ButtonVariant.secondary}
141	                    >
142	                      Reload
143	                    </Button>
144	                  </FlexItem>
145	                </Flex>
146	              </StackItem>
147	            )}
148	          </Stack>
149	        </SidebarPanel>
150	      )}
151	    </Sidebar>
152	  );
153	};
154	
155	export default SidebarEditor;

